import{_ as e,o as r,c as t,a2 as s}from"./chunks/framework.BS3ZfcoS.js";const u=JSON.parse('{"title":"毕业最后悔的10件事","description":"","frontmatter":{"title":"毕业最后悔的10件事","author":"","collection":"职场成长","series_order":11,"total_chars":756},"headers":[],"relativePath":"career/10-regrets.md","filePath":"career/10-regrets.md"}'),o={name:"career/10-regrets.md"};function n(h,a,i,l,p,d){return r(),t("div",null,[...a[0]||(a[0]=[s('<h2 id="s-550" tabindex="-1">毕业最后悔的10件事系列 <a class="header-anchor" href="#s-550" aria-label="Permalink to &quot;毕业最后悔的10件事系列 {#s-550}&quot;">​</a></h2><p>共3个视频</p><h3 id="s-551" tabindex="-1">毕业最后悔的10件事（一）——学历与室友 <a class="header-anchor" href="#s-551" aria-label="Permalink to &quot;毕业最后悔的10件事（一）——学历与室友 {#s-551}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-552" tabindex="-1">1. 没有好学历在大城市找工作确实艰难——好好学习仍是硬道理 <a class="header-anchor" href="#s-552" aria-label="Permalink to &quot;1. 没有好学历在大城市找工作确实艰难——好好学习仍是硬道理 {#s-552}&quot;">​</a></h4><p>**2. **花太多精力纠结寝室关系——室友是随机分配的，主动认识的朋友质量更高（如Learning Partner和学长）</p><h4 id="s-553" tabindex="-1">3. 鼓励多参加活动多表达自己，主动结交你喜欢的人做朋友 <a class="header-anchor" href="#s-553" aria-label="Permalink to &quot;3. 鼓励多参加活动多表达自己，主动结交你喜欢的人做朋友 {#s-553}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「室友根本就不是你选的，是随机分配的，你主动挑选认识的朋友就会好很多」</em></p><p><strong>行动指南</strong></p><p>主动参加活动结交志同道合的朋友，不要困在寝室关系中</p><h3 id="s-554" tabindex="-1">毕业最后悔的10件事（二）——风口·学生证·阅读·实习 <a class="header-anchor" href="#s-554" aria-label="Permalink to &quot;毕业最后悔的10件事（二）——风口·学生证·阅读·实习 {#s-554}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **活在自己的小世界错过风口——要在外部世界变化时积极参与，在公众平台做输出积累个人品牌</p><h4 id="s-555" tabindex="-1">2. 没有利用好学生证红利——社会对学生群体太友善，各种折扣免费要尽早享受 <a class="header-anchor" href="#s-555" aria-label="Permalink to &quot;2. 没有利用好学生证红利——社会对学生群体太友善，各种折扣免费要尽早享受 {#s-555}&quot;">​</a></h4><p>**3. **看书不够多——工作后没时间没精力阅读，大学是阅读的黄金期，一年至少看12本</p><h4 id="s-556" tabindex="-1">4. 四年没有实习——有实习经验在校招社招时大大加分 <a class="header-anchor" href="#s-556" aria-label="Permalink to &quot;4. 四年没有实习——有实习经验在校招社招时大大加分 {#s-556}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「四年你竟然一个实习都没有找过，你是猪吗」</em></p><p><strong>行动指南</strong></p><p>在校期间多输出积累、多找实习、充分利用学生身份、制定阅读计划</p><h3 id="s-557" tabindex="-1">毕业最后悔的10件事（三）——变美·兴趣·专业课·职业规划 <a class="header-anchor" href="#s-557" aria-label="Permalink to &quot;毕业最后悔的10件事（三）——变美·兴趣·专业课·职业规划 {#s-557}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **女生要趁年轻时变美——不是容貌焦虑，而是内在形象与外在形象统一让人更快乐自信</p><h4 id="s-558" tabindex="-1">2. 培养兴趣爱好——可能发展成副业甚至超过主业收入 <a class="header-anchor" href="#s-558" aria-label="Permalink to &quot;2. 培养兴趣爱好——可能发展成副业甚至超过主业收入 {#s-558}&quot;">​</a></h4><h4 id="s-559" tabindex="-1">3. 专业课学扎实——真正的素养靠平时点滴积累，不是临时抱佛脚 <a class="header-anchor" href="#s-559" aria-label="Permalink to &quot;3. 专业课学扎实——真正的素养靠平时点滴积累，不是临时抱佛脚 {#s-559}&quot;">​</a></h4><h4 id="s-560" tabindex="-1">4. 职业规划越早越好，但不是靠想而是靠做——多做事情多了解自己才有可能想清楚 <a class="header-anchor" href="#s-560" aria-label="Permalink to &quot;4. 职业规划越早越好，但不是靠想而是靠做——多做事情多了解自己才有可能想清楚 {#s-560}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「做好职业规划它不是靠想的，你是要多做一些事情多了解自己才有可能想清楚」</em></p><p><strong>行动指南</strong></p><p>趁在校锻炼变美、培养兴趣、学好专业课、尽早尝试不同方向</p>',31)])])}const m=e(o,[["render",n]]);export{u as __pageData,m as default};
